#include<stdio.h>
int main()
{
int n,i,j,pos,counter;
int criminals[100];
counter=0;
scanf("%d%d",&n,&pos);
for(i=0;i<n;i++)
scanf("%d",&criminals[i]);
if(criminals[pos-1]==1)
counter+=1;
for(j=1;j<=i;j++)
{
if((pos-1-j>=0)&&(pos-1+j<n)&&((criminals[pos-1-j]&criminals[pos-1+j])==1))
counter+=2;
else if((pos-1-j>=0)&&(pos-1+j>=n)&&(criminals[pos-1-j]==1))
counter+=1;
else if((pos-1-j<0)&&(pos-1+j<n)&&(criminals[pos-1+j]==1))
counter+=1;}
printf("%d",counter);
return 0;}

